const rows = $input.all().map(i=>i.json);
const istOffset = 5.5*60*60*1000;
const INCOME = 140700;
const TEST_TARGET = "";
const MONTHS=['January','February','March','April','May','June','July','August','September','October','November','December'];

const now = new Date();
const nowIST = new Date(now.getTime()+istOffset);
let ty = nowIST.getUTCFullYear();
let tmIdx = nowIST.getUTCMonth() - 1;   // previous calendar month
if(tmIdx < 0){ tmIdx = 11; ty -= 1; }
let targetKey = ty + '-' + String(tmIdx+1).padStart(2,'0');

if(TEST_TARGET){
  targetKey = TEST_TARGET;
  ty = parseInt(TEST_TARGET.split('-')[0]);
  tmIdx = parseInt(TEST_TARGET.split('-')[1]) - 1;
}

let py = ty, pmIdx = tmIdx - 1;
if(pmIdx < 0){ pmIdx = 11; py -= 1; }
const priorKey = py + '-' + String(pmIdx+1).padStart(2,'0');
const month_name = MONTHS[tmIdx] + ' ' + ty;

const mkey = r => {
  if(r.month_key) return r.month_key;
  if(!r.timestamp) return null;
  const t = new Date(r.timestamp);
  if(isNaN(t.getTime())) return null;
  const ist = new Date(t.getTime()+istOffset);
  return ist.getUTCFullYear()+'-'+String(ist.getUTCMonth()+1).padStart(2,'0');
};

const target = rows.filter(r => mkey(r)===targetKey);
const prior  = rows.filter(r => mkey(r)===priorKey);

if(target.length===0){
  return [{ json: { hasData:false, month_key: targetKey,
    noDataText: `🎯 Monthly Report — ${month_name}\n\nNo expenses were logged in ${month_name}. Nothing to report this month.` }}];
}

const sum = a => a.reduce((s,r)=>s+(parseFloat(r.amount)||0),0);
const total_spend = Math.round(sum(target));
const prior_spend = Math.round(sum(prior));
const total_income = INCOME;
const savings = total_income - total_spend;
const savings_rate = total_income>0 ? Math.round(savings/total_income*100) : 0;
const mom_change_pct = prior_spend>0 ? Math.round((total_spend-prior_spend)/prior_spend*100) : null;

const cat={};
for(const r of target){ const c=r.category||'Uncategorized'; cat[c]=(cat[c]||0)+(parseFloat(r.amount)||0); }
const category_breakdown = Object.entries(cat).sort((a,b)=>b[1]-a[1])
  .map(([category,amount])=>({category, amount:Math.round(amount), pct: total_spend>0?Math.round(amount/total_spend*100):0}));
const top3 = category_breakdown.slice(0,3);
const top_3_leaks = top3.map(c=>`${c.category} ₹${c.amount} (${c.pct}%)`).join('; ');

const needTotal = sum(target.filter(r=>(r.need_or_want||'').toLowerCase()==='need'));
const need_pct = total_spend>0 ? Math.round(needTotal/total_spend*100):0;

const stats = {
  month_key: targetKey, month_name, total_income, total_spend, prior_spend,
  savings, savings_rate, mom_change_pct, need_pct, want_pct: 100-need_pct,
  category_breakdown, top_3_leaks, transaction_count: target.length
};
return [{ json: { hasData:true, ...stats, statsJson: JSON.stringify(stats) } }];

const raw = $input.first().json;
let narrative = (raw.candidates?.[0]?.content?.parts?.[0]?.text||'').trim();
const a = $('Aggregate Month').first().json;
if(!narrative){
  narrative = `🎯 Monthly Report — ${a.month_name}\nSpent ₹${a.total_spend} of ₹${a.total_income} income (saved ${a.savings_rate}%)`;
}
return [{ json: {
  month_key: a.month_key,
  total_income: a.total_income,
  total_spend: a.total_spend,
  savings_rate: a.savings_rate,
  mom_change_pct: (a.mom_change_pct===null || a.mom_change_pct===undefined) ? 'N/A' : a.mom_change_pct,
  top_3_leaks: a.top_3_leaks,
  recommendations: narrative,
  report_sent: true
}}];
